import { Component, Event, EventEmitter, h, JSX, Prop, State, Watch } from '@stencil/core';

import {
  buildCalendarYear,
  buildCalendarYearWithoutDate,
  CalendarType,
  CalYear,
  dateConst,
  DateValidationResult,
  Item,
  Period,
  updateYearsOnCalendarChange,
  Week
} from '@src/utils/mx-utils/calendar-service';
import { MxSingleSelectCustomEvent } from '@src/components';
import { isNullOrUndefined, isNullOrUndefinedOrEmptyString } from '@src/utils/mx-utils/utils';


interface IPeriodWithList {
  period: Period;
  periods: JSX.Element;
}

interface IWeekWithList {
  week: Week;
  weeks: JSX.Element;
}

@Component({
  tag: 'mx-ad-fiscal-calendar',
  styleUrl: 'mx-calendar.css'
})
export class MxAdFiscalCalendar {

  /** Stores current calendar type. **/
  @Prop() readonly calType: CalendarType = CalendarType.AD;

  /** Stores all years in the dropdown. **/
  @Prop() readonly years: Array<Item>;

  /** Stores input year. **/
  @Prop() readonly year: number;

  /** Sets min date that can be chosen. **/
  @Prop() readonly minActiveDate: Date | string;

  /** Sets max date that can be chosen. **/
  @Prop() readonly maxActiveDate: Date | string;

  /** Sets the date the calendar should open to when no value is provided. */
  @Prop() readonly visualSelectedDate: Date;

  /** Sets disabled state to the component. **/
  @Prop() readonly disabled: boolean;

  /** Stores current date **/
  @Prop() readonly value: Date;

  /// props relevant for ad/fiscal only
  /** Hides Day's selection in Ad Calendar when true **/
  @Prop() readonly hideAdDays: boolean = false;

  /** Hides Day's selection in Fiscal Calendar when true **/
  @Prop() readonly hideFiscalDays: boolean = false;

  /** Use only when hideAdDays/hideFiscalDays is true. Sets selected day of week (1-Mon, 2-Tue, 3-Wed ...)  **/
  @Prop() readonly customOffset: number = 0;

  /** Sets handler for chose the date**/
  @Event() selectDate: EventEmitter<Date>;

  /** Sets handler for the component ready and rendered**/
  @Event() ready: EventEmitter<null>;

  /** Sets handler for the component loosing focus **/
  @Event() calendarBlur: EventEmitter<null>;

  /** Stores current year data of selected calendar type. **/
  @State() yearData: CalYear;
  @Watch('yearData')
  onYearDataChange(yearData: CalYear) {
    this.calculateYearData(yearData);
    updateYearsOnCalendarChange(this.years, yearData.calYear);
  }
  /** Stores days in months. **/
  @State() weekDaysNames: Array<string> = dateConst.daysOfWeekNames;

  /** Selected period. **/
  @State() period: Period;

  /** Selected week. **/
  @State() week: Week;

  /** Selected Date. **/
  @State() day: Date;

  /** Watches for calendar type changes **/
  @Watch('calType')
  handleCalTypeChange() {
    // determine if we are technically before the start of the year if no passed in date.
    if (this.shouldUsePreviousYearAndIsUninitialized()) {
      this.calculateYearData(this.yearData, new Date().getFullYear() - 1);
    } else {
      this.calculateYearData(this.yearData, this.year);
    }
  }

  componentWillLoad() {
    if (this.value != null) {
      this.day = this.value;
    } else if (this.visualSelectedDate != null) {
      this.day = this.visualSelectedDate;
    }

    // determine if we are technically before the start of the year if no passed in date.
    if (this.shouldUsePreviousYearAndIsUninitialized()) {
      this.calculateYearData(this.yearData, new Date().getFullYear() - 1);
    } else {
      this.calculateYearData(this.yearData);
    }
  }

  componentDidLoad() {
    this.ready.emit();
  }

  // Determines if we are in the previous year based off calendar type.
  private shouldUsePreviousYearAndIsUninitialized() {
    const now: Date = new Date();

    // We need to check to current year start and end dates to ensure
    // we are in the correct "year" as it relates to the ad/fiscal cal
    const startAndEndDateThisYear = buildCalendarYearWithoutDate(now.getFullYear(), this.dateOffset(this.calType));

    return this.value == null && this.visualSelectedDate == null && startAndEndDateThisYear.startDate > now;
  }

  private readonly calculateYearData = (yearData: CalYear, currentYearOverride?: number): void => {
    const dateOffset: number = this.dateOffset(this.calType);
    // Prioritize value over visualSelectedDate when calculating yearData
    const usedValue = this.value ? this.value : this.visualSelectedDate;
    if (usedValue == null || !isNullOrUndefined(currentYearOverride)) {
      const currentYear = currentYearOverride || (yearData != null ? yearData.calYear : this.year);
      yearData = buildCalendarYearWithoutDate(currentYear, dateOffset);
    } else {
      if (yearData == null) {
        yearData = buildCalendarYear(usedValue, dateOffset);
      }
      // Set period and week as "selected" only if value is set (not just visualSelectedDate)
      if (!isNullOrUndefined(this.value)) {
        yearData.periods.forEach((p: Period) => {
          if (p.startDate <= this.day && p.endDate >= this.day) {
            this.period = p;
            p.weeks.forEach((w: Week) => {
              if (w.startDate <= this.day && w.endDate >= this.day) {
                this.week = w;
              }
            });
          }
        });
      }
    }
    // this.yearData will be undefined on componentWillLoad(), so let's set it to yearData
    if (isNullOrUndefined(this.yearData) || !isNullOrUndefined(currentYearOverride)) {
      this.yearData = { ...yearData };
    }
  };

  private readonly yearChangeHandler = (e: MxSingleSelectCustomEvent<any>): void => {
    this.composeYearDataByYear(parseInt(e.detail.value), this.calType);
  };

  private readonly composeYearDataByYear = (currentYear: number, calType: CalendarType): void => {
    this.yearData = {
      ...buildCalendarYearWithoutDate(currentYear, this.dateOffset(calType))
    };
  };

  private readonly dateOffset = (calType: CalendarType): number => {
    return calType === CalendarType.AD ? 3 : 0;
  };

  private readonly escHandler = (e: KeyboardEvent): void => {
    if (e.code === 'Escape') {
      this.calendarBlur.emit(null);
    }
  };

  private readonly selectPeriod = (p: Period): void => {
    this.period = p;
    this.week = null;
    this.day = null;
  };

  private readonly selectWeek = (w: Week, hideDays: boolean): void => {
    this.week = w;
    this.day = null;
    if (this.period == null || this.period.weeks.indexOf(w) < 0) {
      this.period = this.yearData.periods.filter((p: Period) => p.period === w.period)[0];
    }
    if (hideDays) {
      if (this.customOffset > 0) {
        this.selectDate.emit(w.startDate.addDays(this.calculateDaysToAdd()));
      } else {
        this.selectDate.emit(w.startDate);
      }
    }
  };

  private readonly composeAndPickPeriod = (now: Date): IPeriodWithList => {
    let period: Period = null;
    let firstDisabledPeriodPicked = false;
    let selectedPeriodPicked = false;

    const periods: JSX.Element = this.yearData.periods.map((p: Period) => {
      const minPResult: DateValidationResult =
        dateConst.validateMinMax(p.startDate, this.minActiveDate, this.maxActiveDate);
      const maxPResult: DateValidationResult =
        dateConst.validateMinMax(p.endDate, this.minActiveDate, this.maxActiveDate);

      let periodDisabled = !(minPResult.valid || maxPResult.valid);
      const currentPeriod = p.startDate <= now && p.endDate >= now;
      const selected = this.period != null && p.year === this.period.year && p.period === this.period.period;

      if (periodDisabled && !minPResult.minValid && !maxPResult.maxValid && this.minActiveDate !== this.maxActiveDate) {
        periodDisabled = false;
      }

      if (!periodDisabled && !firstDisabledPeriodPicked) {
        period = p;
        firstDisabledPeriodPicked = true;
      }

      if (selected) {
        period = p;
        selectedPeriodPicked = true;
      }

      // Select period containing this.day (from visualSelectedDate) or current period if not already selected
      if (!selectedPeriodPicked && (this.day && p.startDate <= this.day && p.endDate >= this.day || currentPeriod)) {
        period = p;
      }

      return <kds-button
        key={p.year + '_' + p.period}
        type='button'
        kind='tertiary'
        disabled={periodDisabled}
        onClick={(): void => this.selectPeriod(p)}
        button-class={periodDisabled ? 'text-quaternary' : ''}
        class={{
          'mx-calendar__day mx-calendar__day_period kds-Text--s': true,
          'mx-calendar__day_today': currentPeriod,
          'mx-calendar__day_selected': selected
        }}>{p.period}</kds-button>;
    });

    return { period, periods };
  };

  private readonly composeAndPickWeek = (period: Period, now: Date, hideDays: boolean): IWeekWithList => {
    let week = null;
    let firstDisabledWeekPicked: boolean = false;
    let selectedWeekPicked: boolean = false;

    const weeks: JSX.Element = period?.weeks?.map((w: Week, i: number) => {
      const minWResult: DateValidationResult =
        dateConst.validateMinMax(w.startDate, this.minActiveDate, this.maxActiveDate);
      const maxWResult: DateValidationResult =
        dateConst.validateMinMax(w.endDate, this.minActiveDate, this.maxActiveDate);
      const weekDisabled: boolean = !(minWResult.valid || maxWResult.valid);
      const currentWeek: boolean = w.startDate <= now && w.endDate >= now;
      const selectedWeek: boolean = this.week &&
        this.week.week === w.week &&
        w.period === period.period &&
        this.period != null &&
        period.year === this.period.year;

      if (!weekDisabled && !firstDisabledWeekPicked) {
        week = w;
        firstDisabledWeekPicked = true;
      }

      if (selectedWeek) {
        week = w;
        selectedWeekPicked = true;
      }

      // Select week containing this.day (from visualSelectedDate) or current week if not already selected
      if (!selectedWeekPicked && (this.day && w.startDate <= this.day && w.endDate >= this.day || currentWeek)) {
        week = w;
      }

      return <div class='mx-calendar__day mx-calendar__day_period'>
        <kds-button
          key={period.year + '_' + w.period + '_' + w.week}
          kind='tertiary'
          type='button'
          disabled={weekDisabled}
          onKeyDown={(e: KeyboardEvent): void => {
            // We don't want to exit out of the calendar if we're holding down shift to go back a day
            // It's incredibly annoying to write a unit test for the following keyboard interaction given it's being
            // done on a button inside a function. Let's skip it for now.
            /* istanbul ignore next */
            if (hideDays && e.code === 'Tab' && !e.shiftKey) {
              const date: Date = w.startDate.addDays(this.calculateDaysToAdd());
              const nextDay: Date = date.addDays(7);
              const maxDate: Date = new Date(this.maxActiveDate);
              const nextDayIsDisabled: boolean = !dateConst.dateIsInvalid(maxDate) && nextDay > maxDate;
              const isLastWeekInPeriod: boolean = i === period.weeks.length - 1;
              if (isLastWeekInPeriod || nextDayIsDisabled) {
                e.preventDefault();
                this.calendarBlur.emit(null);
              }
            }
          }}
          onClick={() => this.selectWeek(w, hideDays)}
          button-class={weekDisabled ? 'text-quaternary' : ''}
          class={{
            'mx-calendar__day mx-calendar__day_period kds-Text--s': true,
            'mx-calendar__day_today': currentWeek,
            'mx-calendar__day_selected': selectedWeek
          }}>{i + 1}</kds-button>
        <div class='mx-calendar__day-hint text-neutral-more-prominent'>({w.week})</div>
      </div>;
    });

    return { week, weeks };
  };

  private readonly composeDays = (week: Week, now): JSX.Element => {
    if (week == null) {
      return [];
    }
    return dateConst.rangeIncluding(0, this.weekDaysNames.length - 1).map((i: number) => {
      const date: Date = week.startDate?.addDays(i);
      const vResult: DateValidationResult = dateConst.validateMinMax(date, this.minActiveDate, this.maxActiveDate);
      const dateDisabled: boolean = !vResult.valid;
      return <kds-button
        kind='tertiary'
        type='button'
        disabled={dateDisabled}
        onKeyDown={(e: KeyboardEvent): void => {
          // We don't want to exit out of the calendar if we're holding down shift to go back a day
          // It's incredibly annoying to write a unit test for the following keyboard interaction given it's being
          // done on a button inside a function. Let's skip it for now.
          /* istanbul ignore next */
          if (e.code === 'Tab' && !e.shiftKey) {
            const nextDay: Date = date.addDays(1);
            const maxDate: Date = new Date(this.maxActiveDate);
            if (dateConst.isSameDate(week.endDate, date) || (!dateConst.dateIsInvalid(maxDate) && nextDay > maxDate)) {
              e.preventDefault();
              this.calendarBlur.emit(null);
            }
          }
        }}
        onClick={(): void => {
          if (this.period == null) {
            this.period = this.yearData.periods.filter((p: Period) => p.period === week.period)[0];
          }
          if (this.week == null) {
            this.week = week;
          }
          this.day = date;
          this.selectDate.emit(date);
        }}
        button-class={dateDisabled ? 'text-quaternary' : ''}
        class={{
          'mx-calendar__day kds-Text--s': true,
          'mx-calendar__day_today': dateConst.isSameDate(date, now),
          'mx-calendar__day_selected': !isNullOrUndefined(this.value) && dateConst.isSameDate(date, this.day)
        }}>{this.weekDaysNames[date.getDay()]}</kds-button>;
    });
  };

  render() {
    const currentYear: number = this.yearData != null ? this.yearData.calYear : this.year;

    const now: Date = new Date();

    const hideDays: boolean = (this.calType === CalendarType.AD && this.hideAdDays) ||
      (this.calType === CalendarType.FISCAL && this.hideFiscalDays);

    const periodsAndPickedPeriod: IPeriodWithList = this.composeAndPickPeriod(now);
    const weeksAndPickedWeek: IWeekWithList = this.composeAndPickWeek(periodsAndPickedPeriod.period, now, hideDays);

    const daySelected = hideDays || this.day != null;
    const dateFullySelected = this.period != null && this.week != null && daySelected;
    const clearLinkDisabled = this.disabled || isNullOrUndefinedOrEmptyString(this.value) || !dateFullySelected;

    return <div class='mx-calendar'>
      <div class='mx-calendar__controls mx-calendar__controls_ad-fiscal'>
        <mx-single-select
          class='mx-calendar__year'
          isDisabled={this.disabled}
          items={this.years}
          isCompact={true}
          itemSelected={this.years[this.years.findIndex((y) => currentYear === parseInt(y.value + ''))]}
          onItemChange={this.yearChangeHandler}
          onKeyDown={this.escHandler}
          placeHolder='Year'
          width='81px'
          list-width='100%'/>

        <div class='mx-calendar__clear'>
          <kds-link
            class={{ 'mx-calendar__clear_is-disabled': clearLinkDisabled }}
            onClick={(e) => {
              e.preventDefault();
              if (!clearLinkDisabled) {
                this.selectDate.emit(null);
                this.period = null;
                this.week = null;
                this.day = null;
              }
            }}>Clear
          </kds-link>
        </div>
      </div>
      <div class='mx-calendar__row mx-calendar__row_divider mx-calendar__row_flex border-neutral-less-subtle'>
        <div class='mx-calendar__block-header text-secondary'>Period</div>
        <div
          class='mx-calendar__items'
          tabindex={0}
          onKeyDown={this.escHandler}>{periodsAndPickedPeriod.periods}</div>
      </div>
      <div class={{
        'mx-calendar__row mx-calendar__row_flex': true,
        'mx-calendar__row_divider border-neutral-less-subtle': !hideDays
      }}>
        <div class='mx-calendar__block-header text-secondary'>Week</div>
        <div class='mx-calendar__items' tabindex={0} onKeyDown={this.escHandler}>{weeksAndPickedWeek.weeks}</div>
      </div>
      {
        hideDays ? <span /> : <div class='mx-calendar__row mx-calendar__row_flex'>
          <div class='mx-calendar__block-header text-secondary'>Day</div>
          <div
            class='mx-calendar__items'
            tabindex={0}
            onKeyDown={this.escHandler}>{this.composeDays(weeksAndPickedWeek.week, now)}</div>
        </div>
      }
    </div>;
  }

  private calculateDaysToAdd(): number {
    return this.calType === CalendarType.AD ? this.customOffset - 3 : this.customOffset;
  }
}
