import { Component, Event, EventEmitter, h, Prop, State, Watch } from '@stencil/core';
import { MxSingleSelectCustomEvent } from '@src/components';
import {
  dateConst,
  DateValidationResult,
  IMonthDay,
  Item,
  updateYearsOnCalendarChange,
  yearAccepted
} from '@src/utils/mx-utils/calendar-service';
import { isNullOrUndefinedOrEmptyString } from '@src/utils/mx-utils/utils';

@Component({
  tag: 'mx-gregorian-calendar',
  styleUrl: 'mx-calendar.css'
})
export class MxGregorianCalendar {

  /** Stores all years in the dropdown. **/
  @Prop() readonly years: Array<Item>;

  /** Stores input year. **/
  @Prop() readonly year: number;

  /** Stores input month **/
  @Prop() readonly month: string;

  /** Sets min date that can be chosen. **/
  @Prop() readonly minActiveDate: Date | string;

  /** Sets max date that can be chosen. **/
  @Prop() readonly maxActiveDate: Date | string;

  /** Sets disabled state to the component. **/
  @Prop() readonly disabled: boolean;

  /** Stores current date **/
  @Prop() readonly value: Date;

  /** Sets handler for chose the date**/
  @Event() selectDate: EventEmitter<Date>;

  /** Sets handler for the component ready and rendered **/
  @Event() ready: EventEmitter<null>;

  /** Sets handler for the component loosing focus **/
  @Event() calendarBlur: EventEmitter<null>;

  /** Sets handler for the month change **/
  @Event() monthChange: EventEmitter<{ oldMonth: number, newMonth: number }>;

  /** Sets handler for the year change **/
  @Event() yearChange: EventEmitter<{ value: string }>;

  /** Stores current year. **/
  @State() currentYear: number;

  /** Stores current month. **/
  @State() currentMonth: string;

  /** Stores months names. **/
  @State() monthNames: Array<string> = dateConst.monthNames;

  /** Stores week days names. **/
  @State() weekDaysNames: Array<string> = dateConst.daysOfWeekNames;

  /** Stores focused date **/
  @State() focusedValue: Date;

  @Watch('year')
  watchYear(newYear: number) {
    this.currentYear = newYear;
  }

  @Watch('month')
  watchMonth(newMonth: string) {
    this.currentMonth = newMonth;
  }

  componentWillLoad() {
    this.currentYear = this.year;
    this.currentMonth = this.month;
    updateYearsOnCalendarChange(this.years, this.year);
  }

  componentDidLoad() {
    this.ready.emit();
  }

  private readonly yearChangeHandler = (e: MxSingleSelectCustomEvent<any>): void => {
    const selectedYear = parseInt(e.detail.value);
    this.currentYear = selectedYear;
    this.yearChange.emit({ value: e.detail.value });
  };

  private readonly prevMonth = (): void => {
    const currentMonthNum: number = this.monthNames.indexOf(this.currentMonth);
    const oldMonth = currentMonthNum;

    let targetYear = this.currentYear;
    let targetMonth = currentMonthNum - 1;

    if (currentMonthNum === 0) {
      if (!yearAccepted(this.minActiveDate, this.maxActiveDate, this.currentYear - 1)) {
        return;
      }
      targetYear = this.currentYear - 1;
      targetMonth = dateConst.maxMonthIndex;
    }

    // Check if the last day of the target month would be before minActiveDate
    if (this.minActiveDate) {
      const minDate = new Date(this.minActiveDate);
      const lastDayOfTargetMonth = new Date(targetYear, targetMonth + 1, 0);
      if (lastDayOfTargetMonth < minDate) {
        return;
      }
    }

    this.currentMonth = this.monthNames[targetMonth];
    const newMonth = this.monthNames.indexOf(this.currentMonth);

    this.monthChange.emit({ oldMonth, newMonth });
  };

  private readonly nextMonth = (): void => {
    const currentMonthIndex: number = this.monthNames.indexOf(this.currentMonth);
    const oldMonth = currentMonthIndex;

    let targetYear = this.currentYear;
    let targetMonth = currentMonthIndex + 1;

    if (currentMonthIndex === dateConst.maxMonthIndex) {
      if (!yearAccepted(this.minActiveDate, this.maxActiveDate, this.currentYear + 1)) {
        return;
      }
      targetYear = this.currentYear + 1;
      targetMonth = 0;
    }

    // Check if the first day of the target month would be after maxActiveDate
    if (this.maxActiveDate) {
      const maxDate = new Date(this.maxActiveDate);
      const firstDayOfTargetMonth = new Date(targetYear, targetMonth, 1);
      if (firstDayOfTargetMonth > maxDate) {
        return;
      }
    }

    this.currentMonth = this.monthNames[targetMonth];
    const newMonth = this.monthNames.indexOf(this.currentMonth);

    this.monthChange.emit({ oldMonth, newMonth });
  };

  private readonly composeCurrentMonthDays = (): Array<IMonthDay> => {
    const currentMonthIndex: number = this.monthNames.indexOf(this.currentMonth);
    const today: Date = new Date();

    // add all days of the current moth
    const lastDayOfCurrentMonth: Date = currentMonthIndex === dateConst.maxMonthIndex
      ? new Date(this.currentYear + 1, 0, 0)
      : new Date(this.currentYear, currentMonthIndex + 1, 0);

    const currMonthMaxDays: number = lastDayOfCurrentMonth.getDate();
    let days: Array<IMonthDay> = dateConst.rangeIncluding(1, currMonthMaxDays).map((d) => {
      const date: Date = new Date(this.currentYear, currentMonthIndex, d);
      return {
        selected: dateConst.isSameDate(this.value, date),
        focused: dateConst.isSameDate(this.focusedValue, date),
        today: dateConst.isSameDate(today, date),
        canSelect: dateConst.validateMinMax(date, this.minActiveDate, this.maxActiveDate).valid,
        isCurrentMonth: true,
        label: d
      };
    });

    // add days from the previous month starting from Sunday
    const lastDayOfPrevMonth: Date = new Date(this.currentYear, currentMonthIndex, 0);
    const lastDayOfPrevMonthWeekDay: number = lastDayOfPrevMonth.getDay();

    if (lastDayOfPrevMonthWeekDay < 6) {
      const lastDayPrevMonthDayOfMoth: number = lastDayOfPrevMonth.getDate();
      const startOfWeekDayOfMoth: number = lastDayPrevMonthDayOfMoth - lastDayOfPrevMonthWeekDay;
      const daysToPrepend: Array<IMonthDay> = dateConst
        .rangeIncluding(startOfWeekDayOfMoth, lastDayPrevMonthDayOfMoth)
        .map((r) => {
          const date: Date = currentMonthIndex === 0
            ? new Date(this.currentYear - 1, dateConst.maxMonthIndex, r)
            : new Date(this.currentYear, currentMonthIndex - 1, r);

          return {
            selected: dateConst.isSameDate(this.value, date),
            focused: dateConst.isSameDate(this.focusedValue, date),
            today: dateConst.isSameDate(today, date),
            canSelect: dateConst.validateMinMax(date, this.minActiveDate, this.maxActiveDate).valid,
            isCurrentMonth: false,
            label: r
          };
        });

      days = [...daysToPrepend, ...days];
    }

    // add days from the next month till from Saturday
    const firstDayNextMonth: Date = currentMonthIndex === dateConst.maxMonthIndex
      ? new Date(this.currentYear + 1, 0, 1)
      : new Date(this.currentYear, currentMonthIndex + 1, 1);

    const firstDayNextMonthDayOfWeek: number = firstDayNextMonth.getDay();

    if (firstDayNextMonthDayOfWeek !== 0) {
      const daysToAppend: Array<IMonthDay> = dateConst.rangeIncluding(1, 7 - firstDayNextMonthDayOfWeek)
        .map((r) => {
          const date: Date =
            currentMonthIndex === dateConst.maxMonthIndex
              ? new Date(this.currentYear + 1, 0, r)
              : new Date(this.currentYear, currentMonthIndex + 1, r);
          return {
            selected: dateConst.isSameDate(this.value, date),
            focused: dateConst.isSameDate(this.focusedValue, date),
            today: dateConst.isSameDate(today, date),
            canSelect: dateConst.validateMinMax(date, this.minActiveDate, this.maxActiveDate).valid,
            isCurrentMonth: false,
            label: r
          };
        });

      days.push(...daysToAppend);
    }

    return days;
  };

  private readonly focusNext = (focused: Date): void => {
    const dateValidationResult: DateValidationResult =
      dateConst.validateMinMax(focused, this.minActiveDate, this.maxActiveDate);

    if (dateValidationResult.valid) {
      this.currentYear = focused.getFullYear();
      this.currentMonth = dateConst.monthNames[focused.getMonth()];
      this.focusedValue = focused;
    }
  };

  private readonly calendarGotFocus = (): void => {
    const focusedValue: Date = this.initFocusedValue();
    const currentMonth: number = this.monthNames.indexOf(this.currentMonth);
    if (focusedValue.getFullYear() === this.currentYear && focusedValue.getMonth() === currentMonth) {
      this.focusedValue = focusedValue;
      return;
    }

    this.focusedValue = new Date(this.currentYear, currentMonth, 1);
  };

  private readonly keyAction = (e: KeyboardEvent): void => {
    if (e.code !== 'Tab') {
      e.preventDefault();
    }

    switch (e.code) {
      case 'Enter':
      case 'Space':
        this.handleEnterOrSpace();
        break;
      case 'ArrowLeft':
        this.handleArrow(-1);
        break;
      case 'ArrowRight':
        this.handleArrow(1);
        break;
      case 'ArrowDown':
        this.handleArrow(7);
        break;
      case 'ArrowUp':
        this.handleArrow(-7);
        break;
      case 'Home':
        this.handleHomeKey();
        break;
      case 'End':
        this.handleEndKey();
        break;
      case 'PageUp':
        this.handlePageKey(-1, e.altKey);
        break;
      case 'PageDown':
        this.handlePageKey(1, e.altKey);
        break;
      case 'Tab':
        this.handleTabKey(e);
        break;
      case 'Escape':
        break;
    }
  };
  private handleEnterOrSpace(): void {
    this.selectDate.emit(this.focusedValue);
  }

  private handleArrow(days: number): void {
    if (this.focusedValue != null) {
      this.focusNext(this.focusedValue.addDays(days));
    }
  }

  private handleHomeKey(): void {
    if (this.focusedValue != null) {
      this.focusNext(new Date(
        this.focusedValue.getFullYear(),
        this.focusedValue.getMonth(),
        1
      ));
    }
  }

  private handleEndKey(): void {
    if (this.focusedValue != null) {
      this.focusNext(new Date(
        this.focusedValue.getFullYear(),
        this.focusedValue.getMonth() + 1,
        0
      ));
    }
  }

  private handlePageKey(monthDelta: number, isAlt: boolean): void {
    if (this.focusedValue != null) {
      const year = this.focusedValue.getFullYear();
      const month = this.focusedValue.getMonth();
      const date = this.focusedValue.getDate();

      const newDate = isAlt
        ? new Date(year + monthDelta, month, date)
        : new Date(year, month + monthDelta, date);

      this.focusNext(newDate);
    }
  }

  private handleTabKey(e: KeyboardEvent): void {
    if (!e.shiftKey) {
      this.focusedValue = null;
      this.calendarBlur.emit(null);
    }
  }
  private readonly escHandler = (e: KeyboardEvent): void => {
    if (e.code === 'Escape') {
      this.calendarBlur.emit(null);
    }
  };

  private readonly initFocusedValue = (): Date => {
    if (this.value != null) {
      return new Date(this.value);
    }

    const now: Date = new Date();
    const dateValidationResult: DateValidationResult =
      dateConst.validateMinMax(now, this.minActiveDate, this.maxActiveDate);

    if (dateValidationResult.valid) {
      return now;
    }

    const minDate: Date = new Date(this.minActiveDate);
    if (!dateConst.dateIsInvalid(minDate) && now < minDate) {
      return minDate;
    }

    const maxDate: Date = new Date(this.maxActiveDate);
    if (!dateConst.dateIsInvalid(maxDate) && now > maxDate) {
      return maxDate;
    }
  };

  render() {
    const clearLinkDisabled = this.disabled || isNullOrUndefinedOrEmptyString(this.value);

    return <div class='mx-calendar'>
      <div class='mx-calendar__controls'>
        <div class='mx-calendar__month' aria-label='Month navigation'>
          <kds-button
            class='mx-calendar__month-button'
            type='button'
            kind='tertiary'
            compact={true}
            onClick={this.prevMonth}
            onKeyDown={this.escHandler}><kds-icon-caret-left /></kds-button>
          <span class='font-base font-400 kds-Text--m'
            aria-label={`Current month: ${this.currentMonth}`}>
            {this.currentMonth}
          </span>
          <kds-button
            class='mx-calendar__month-button'
            type='button'
            kind='tertiary'
            compact={true}
            onClick={this.nextMonth}
            onKeyDown={this.escHandler}><kds-icon-caret-right /></kds-button>
        </div>

        <mx-single-select
          class='mx-calendar__year'
          aria-label='Select year'
          isDisabled={this.disabled}
          items={this.years}
          isCompact={true}
          onKeyDown={this.escHandler}
          itemSelected={
            this.years[this.years.findIndex((y) => this.currentYear === parseInt(y.value + ''))]
          }
          placeHolder='Year'
          onItemChange={this.yearChangeHandler}
          width='81px'
          list-width='100%' />

        <div class='mx-calendar__clear'>
          <kds-link
            class={{ 'mx-calendar__clear_is-disabled': clearLinkDisabled }}
            aria-disabled={clearLinkDisabled ? 'true' : 'false'}
            onClick={(e) => {
              e.preventDefault();
              !clearLinkDisabled && this.selectDate.emit(null);
            }}>Clear</kds-link>
        </div>
      </div>
      <div class='mx-calendar__weekdays'>
        {this.weekDaysNames.map((wd) => (
          <div class='mx-calendar__week-day-name' role='columnheader' aria-label={wd}>
            {wd}
          </div>))}
      </div>
      <span
        tabindex={0}
        class='mx-calendar__days'
        role='grid'
        aria-label='Calendar day grid'
        onKeyDown={this.keyAction}
        onFocusin={this.calendarGotFocus}>
        {
          this.composeCurrentMonthDays().map((d) => {
            const disabled = !d.isCurrentMonth || !d.canSelect;
            return (
              <kds-button
                type='button'
                kind='tertiary'
                disabled={disabled}
                aria-label={`Select ${d.label} ${this.currentMonth} ${this.currentYear}`}
                onClick={() => {
                  this.selectDate.emit(new Date(this.currentYear, this.monthNames.indexOf(this.currentMonth), d.label));
                }}
                button-class={[
                  disabled ? 'text-quaternary' : ''
                ].join(' ')}
                class={{
                  'mx-calendar__day kds-Text--s': true,
                  'mx-calendar__day_today': d.today,
                  'mx-calendar__day_selected': d.selected,
                  'mx-calendar__day_focused': d.focused
                }}>{d.label}</kds-button>
            );
          })
        }
      </span>
    </div>;
  }
}
